---@class StructLotteryData 抽奖数据
local StructLotteryData = LxClass("StructLotteryData", nil)
function StructLotteryData:StructLotteryData()
    ---@type number 轮次
    self.round = 0
    ---@type number 选择的大奖
    self.guaranteeId = 0
    ---@type number 是否抽中大奖
    self.isGuarantee = 0
    ---@type number 抽奖次数
    self.lotteryCount = 0
    ---@type table key:奖品ID, value:剩余数量(-1表示无限)
    self.poolRemain = {}
end

function StructLotteryData:CreateByPb(pb)
    self.round = pb.round
    self.guaranteeId = pb.guaranteeId
    self.isGuarantee = pb.isGuarantee == 1
    self.lotteryCount = pb.lotteryCount
    local poolRemain = {}
    for i,v in ipairs(pb.poolRemain) do
        poolRemain[v.key] = v.value
    end
    self.poolRemain = poolRemain
end

---@return boolean 是否选择大奖
function StructLotteryData:CheckIsSelGuaranteeId()
    return self.guaranteeId and self.guaranteeId > 0
end

---@return boolean 是否抽中大奖
function StructLotteryData:CheckIsGuarantee()
    return self.isGuarantee
end

---@return boolean 是否显示大奖设置按钮
function StructLotteryData:CheckShowBtnBigRewSet()
    if not self:CheckIsSelGuaranteeId() then return true end
    if self.lotteryCount < 1 then return true end
    return false
end

function StructLotteryData:CheckShowInfo()
    if self:CheckIsSelGuaranteeId() then return true end
    return false
end

return StructLotteryData